# ----------------------------------------------------------------------------
# 3) أدوات مساعدة للعرض
# ----------------------------------------------------------------------------
def md_bold(s: str) -> str:
    """تحويل **نص** من ماركداون إلى <b> HTML، وتنظيف بسيط."""
    if s is None:
        return ""
    s = re.sub(r"\*\*(.+?)\*\*", r"<b>\1</b>", s)
    return s

EVIDENCE_KEYWORDS = [
    (r"مرتفع", "badge-high"),
    (r"جيد|قوي", "badge-high"),
    (r"متوسط", "badge-mid"),
    (r"منخفض|ضعيف", "badge-low"),
]

def evidence_badge(cell: str) -> str:
    """يحوّل نص تقييم الدليل إلى شارة ملوّنة + بقية النص."""
    raw = cell
    cls = "badge-neutral"
    for pattern, badge_cls in EVIDENCE_KEYWORDS:
        if re.search(pattern, cell):
            cls = badge_cls
            break
    label_match = re.search(r"^(مرتفع(?: نسبيًا)?|متوسط(?: إلى جيد)?(?: إلى منخفض)?|منخفض(?: إلى متوسط)?)", cell)
    label = label_match.group(0) if label_match else cell.split("،")[0].split(".")[0][:18]
    rest = cell[len(label):].strip(" ,،")
    html = f'<span class="badge {cls}">{md_bold(label)}</span>'
    if rest:
        html += f'<br><span class="small-muted">{md_bold(rest)}</span>'
    return html

def render_table(header, rows, badge_col=None, key_prefix="t", searchable=True):
    """يعرض جدولًا مخصّصًا بتصميم HTML مع خيار بحث/تصفية."""
    df_rows = rows
    if searchable and len(rows) > 4:
        query = st.text_input(
            "🔎 ابحث ضمن هذا الجدول (بالاسم أو أي كلمة)",
            key=f"{key_prefix}_search",
            placeholder="مثال: عسل، كركمين، تداخل...",
        )
        if query:
            q = query.strip()
            df_rows = [r for r in rows if any(q in str(c) for c in r)]

    html = ['<div class="table-wrap"><table class="report-table"><thead><tr>']
    for h in header:
        html.append(f"<th>{h}</th>")
    html.append("</tr></thead><tbody>")
    for row in df_rows:
        html.append("<tr>")
        for idx, cell in enumerate(row):
            if badge_col is not None and idx == badge_col:
                html.append(f"<td>{evidence_badge(cell)}</td>")
            else:
                html.append(f"<td>{md_bold(cell)}</td>")
        html.append("</tr>")
    html.append("</tbody></table></div>")
    if not df_rows:
        st.info("لا توجد نتائج مطابقة لبحثك.")
    else:
        st.markdown("".join(html), unsafe_allow_html=True)
    return df_rows

def render_text_block(text: str):
    """يعرض نصًا مع تحويل bullet markers البسيطة إن وجدت."""
    text = md_bold(text)
    st.markdown(f'<div class="card">{text.replace(chr(10)+chr(10), "<br><br>")}</div>', unsafe_allow_html=True)

def callout(text: str, kind: str = ""):
    cls = "callout " + kind
    st.markdown(f'<div class="{cls}">{md_bold(text)}</div>', unsafe_allow_html=True)

def flow_diagram(boxes_rows):
    """رسم مبسّط لمخطط تدفق بديل عن mermaid: قائمة من الصفوف، كل صف = قائمة عقد."""
    html = []
    for row in boxes_rows:
        html.append('<div class="flow">')
        for i, node in enumerate(row):
            cls = "flow-box alt" if node.startswith("*") else "flow-box"
            label = node.lstrip("*")
            html.append(f'<div class="{cls}">{label}</div>')
            if i != len(row) - 1:
                html.append('<div class="flow-arrow">←</div>')
        html.append("</div>")
    st.markdown("".join(html), unsafe_allow_html=True)

